[data-resp="callout-label"]{display:inline-flex;align-items:center;gap:8px;font-family:'Frank Ruhl Libre',serif;font-size:clamp(0.9rem,2vw,1rem);font-weight:700;color:#87562E;letter-spacing:0.5px;margin-bottom:10px}
[data-resp="top-btn"]{opacity:1;pointer-events:auto;transition:opacity 0.3s ease, transform 0.25s ease, background 0.25s ease, border-color 0.25s ease, color 0.25s ease, box-shadow 0.25s ease}
[data-resp="top-btn"].js-hidden{opacity:0;pointer-events:none;transform:translateY(10px)}
